const rows = $input.all().map(item => item.json);
const trigger = $('Telegram Trigger').first().json;
const chatId = trigger.message && trigger.message.chat ? trigger.message.chat.id : null;

if (!chatId) throw new Error('Cannot read chat_id from Telegram trigger');

function esc(t) {
  return (t || '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
}

if (!rows.length || !rows[0].job_title) {
  return [{ json: { text: '\u{1F4ED} Keine Stellen in der Datenbank.', chat_id: chatId } }];
}

const medals = ['\u{1F947}','\u{1F948}','\u{1F949}','4\uFE0F\u20E3','5\uFE0F\u20E3','6\uFE0F\u20E3','7\uFE0F\u20E3','8\uFE0F\u20E3','9\uFE0F\u20E3','\u{1F51F}'];
const high = rows.filter(r => r.relevance_score >= 80);
const mid  = rows.filter(r => r.relevance_score >= 50 && r.relevance_score < 80);
const low  = rows.filter(r => r.relevance_score < 50);

const lines = [
  `\u{1F4CA} <b>JobRadar \u2014 Aktuelle Stellen (Top ${rows.length})</b>`,
  ''
];

if (high.length > 0) {
  lines.push('\u{1F525} <b>Hohe Relevanz</b>');
  high.forEach((job, i) => {
    const medal = medals[i] || `${i+1}.`;
    const loc = job.location ? ` | \u{1F4CD} ${esc(job.location)}` : '';
    const wm  = job.work_mode ? ` (${esc(job.work_mode)})` : '';
    lines.push(`${medal} <b>${esc(job.job_title)}</b>`);
    lines.push(`   \u{1F3E2} ${esc(job.company)}${loc}${wm}`);
    lines.push(`   \u2B50 <b>${job.relevance_score}/100</b>`);
    if (job.summary) lines.push(`   \u{1F4AC} <i>${esc(job.summary).substring(0,100)}\u2026</i>`);
    if (job.source_url) lines.push(`   \u{1F517} <a href="${esc(job.source_url)}">\u00D6ffnen</a>`);
    lines.push('');
  });
}

if (mid.length > 0) {
  lines.push('\u2B50 <b>Mittlere Relevanz</b>');
  mid.forEach(job => {
    const link = job.source_url ? ` \u2014 <a href="${esc(job.source_url)}">\u{1F517}</a>` : '';
    lines.push(`\u2022 <b>${esc(job.job_title)}</b> @ ${esc(job.company)} [${job.relevance_score}]${link}`);
  });
  lines.push('');
}

if (low.length > 0) {
  lines.push('\u{1F4CB} <b>Niedrige Relevanz</b>');
  low.forEach(job => {
    const link = job.source_url ? ` <a href="${esc(job.source_url)}">\u{1F517}</a>` : '';
    lines.push(`\u2022 ${esc(job.job_title)} @ ${esc(job.company)}${link}`);
  });
}

return [{ json: { text: lines.join('\n'), chat_id: chatId } }];
